/**
 * Parse one CSV line into fields.
 * @param {string} line
 * @returns {string[]}
 * @throws {TypeError} When line is not a string
 */
export function parseCsvLine(line) {
  if (typeof line !== 'string') {
    throw new TypeError('line must be a string');
  }

  const fields = [];
  let current = '';
  let inQuotes = false;

  for (let index = 0; index < line.length; index += 1) {
    const char = line[index];
    if (char === '"') {
      if (inQuotes && line[index + 1] === '"') {
        current += '"';
        index += 1;
      } else {
        inQuotes = !inQuotes;
      }
      continue;
    }
    if (char === ',' && !inQuotes) {
      fields.push(current);
      current = '';
      continue;
    }
    current += char;
  }

  fields.push(current);
  return fields;
}
